import { Injectable, inject } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { Table } from '../../models';

@Injectable({
  providedIn: 'root'
})
export class TableService extends BaseService<Table> {
  protected getTableName(): string { return 'tables'; }

  // Override per aggiungere filtro is_active
  override async loadData(): Promise<void> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return;

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true)
        .order('created_at', { ascending: false });

      if (error) throw error;
      console.log('📊 TableService.loadData - dati caricati:', data?.length || 0, 'tavoli');
      console.log('📊 Dettaglio versioni:', data?.map(t => ({ id: t.id, version: t.version, floor_plan_id: t.floor_plan_id })));

      this.dataSubject.next(data || []);
    } catch (error: any) {
      console.error(`Error loading ${this.getTableName()}:`, error);
      this.errorSubject.next(error.message);
      this.dataSubject.next([]);
    }
  }

  // Metodi specifici per TableService
  getTables(): Table[] {
    return this.dataSubject.value;
  }

// Modifica getTablesByFloorPlan per accettare versione opzionale
getTablesByFloorPlan(floorPlanId: string, version?: number): Table[] {
  const allTablesForFloor = this.dataSubject.value.filter(t => t.floor_plan_id === floorPlanId);
  console.log(`🔍 getTablesByFloorPlan: floorPlanId=${floorPlanId}, totale tavoli nel dataSubject per questo floorPlan: ${allTablesForFloor.length}`);
  console.log('🔍 Versioni presenti:', allTablesForFloor.map(t => t.version));
  
  const filtered = allTablesForFloor.filter(table => {
    if (version === undefined) return true;
    // Converte entrambi a number per sicurezza
    const tableVersion = Number(table.version);
    const reqVersion = Number(version);
    return tableVersion === reqVersion;
  });
  
  console.log(`🔍 Dopo filtro versione=${version}: ${filtered.length} tavoli`);
  return filtered;
}

  async createTable(table: Omit<Table, 'id' | 'created_at'>): Promise<Table | null> {
    try {
      console.log('📝 Creating table with shape:', table.shape);

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .insert(table)
        .select()
        .single();

      if (error) {
        console.error('❌ Error creating table:', error);
        console.error('❌ Error details:', error.details);
        throw error;
      }

      console.log('✅ Table created successfully');
      await this.loadData();
      return data;
    } catch (error) {
      console.error('💥 Error in createTable:', error);
      return null;
    }
  }

  async updateTable(id: string, updates: Partial<Table>): Promise<boolean> {
    try {
      console.log(`💾 updateTable for table ${id}:`, updates);

      // 🔥 1. AGGIORNAMENTO OTTIMISTICO IMMEDIATO
      const currentTables = this.dataSubject.value;
      const updatedTables = currentTables.map(table =>
        table.id === id ? { ...table, ...updates } : table
      );
      this.dataSubject.next(updatedTables);

      // 2. Aggiornamento database
      const { error } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .update(updates)
        .eq('id', id);

      if (error) {
        console.error('❌ Database error updating table:', error);
        // Ripristina lo stato in caso di errore
        this.dataSubject.next(currentTables);
        throw error;
      }

      console.log(`✅ Table ${id} updated successfully`);

      // 🔥 IMPORTANTE: NON chiamare loadData() - i dati sono già aggiornati
      return true;
    } catch (error) {
      console.error('❌ Error updating table:', error);
      // Solo in caso di errore, ricarica per sincronizzazione
      await this.loadData();
      return false;
    }
  }


  async deleteTable(id: string): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .update({ is_active: false })
        .eq('id', id);

      if (error) throw error;

      await this.loadData();
      return true;
    } catch (error) {
      console.error('❌ Error deleting table:', error);
      return false;
    }
  }

  checkTableOverlap(newTable: Omit<Table, 'id' | 'created_at'>, excludeTableIds?: string | string[]): boolean {
    const tables = this.getTablesByFloorPlan(newTable.floor_plan_id);

    // Converti excludeTableIds in array se è una stringa singola
    const excludeIds = Array.isArray(excludeTableIds)
      ? excludeTableIds
      : excludeTableIds ? [excludeTableIds] : [];

    for (const table of tables) {
      // Salta i tavoli esclusi
      if (excludeIds.includes(table.id)) continue;

      const overlap = this.doTablesOverlap(newTable, table);
      if (overlap) return true;
    }
    return false;
  }


  private doTablesOverlap(table1: any, table2: any): boolean {
    return !(
      table1.position_x + table1.width <= table2.position_x ||
      table1.position_x >= table2.position_x + table2.width ||
      table1.position_y + table1.height <= table2.position_y ||
      table1.position_y >= table2.position_y + table2.height
    );
  }

  // Unione tavoli
  async updateTableOnlineBookable(id: string, isOnlineBookable: boolean): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .update({ is_online_bookable: isOnlineBookable })
        .eq('id', id);

      if (error) throw error;

      await this.loadData();
      return true;
    } catch (error) {
      console.error('❌ Error updating table online bookable status:', error);
      return false;
    }
  }

  getTablesAvailableForOnlineBooking(floorPlanId: string): Table[] {
    return this.getTablesByFloorPlan(floorPlanId)
      .filter(table => table.is_online_bookable && !table.is_merged && table.is_active);
  }

getVisibleTablesByFloorPlan(floorPlanId: string, version?: number): Table[] {
  const allTables = this.getTablesByFloorPlan(floorPlanId, version);
  console.log(`🔍 getVisibleTablesByFloorPlan: floorPlanId=${floorPlanId}, version=${version}, trovati=${allTables.length}`);
  return allTables.filter(table => !table.is_merged || table.parent_table_id === null);
}

  // Nuovo metodo per ottenere la prossima versione disponibile
  async getNextVersion(floorPlanId: string): Promise<number> {
    const tables = this.getTablesByFloorPlan(floorPlanId);
    const maxVersion = tables.reduce((max, t) => Math.max(max, t.version || 1), 1);
    return maxVersion + 1;
  }


  getTableStyle(table: Table): any {
    let borderRadius: string;

    if (table.border_radius !== undefined && table.border_radius !== null) {
      borderRadius = table.border_radius === 50 ? '50%' : `${table.border_radius}px`;
    } else {
      borderRadius = table.shape === 'circle' ? '50%' : '8px';
    }

    // CORREZIONE: assicurati che la rotazione sia sempre applicata
    const rotation = table.rotation || 0;

    const style: any = {
      left: table.position_x + 'px',
      top: table.position_y + 'px',
      width: table.width + 'px',
      height: table.height + 'px',
      'border-radius': borderRadius,
      transform: `rotate(${rotation}deg)` // ← Questo è il transform corretto
    };

    // DEBUG: attiva solo per troubleshooting
    if (rotation !== 0) {
      console.log(`🎨 Tavolo ${table.table_number}: applicata rotazione di ${rotation}°`);
    }

    if (table.is_merged) {
      style['border'] = '3px dashed #ff6b35';
      style['background'] = 'rgba(255, 107, 53, 0.1)';
    }

    if (!table.is_online_bookable) {
      style['background'] = 'repeating-linear-gradient(45deg, var(--primary), var(--smoke-1) 10px, var(--smoke-1) 10px, var(--primary) 20px)';
    }

    return style;
  }

  getTableClass(table: Table, selectedTable: Table | null, selectedTables: Table[], isMergeMode: boolean): string {
    const classes = ['table-element', `shape-${table.shape}`];

    if (selectedTable?.id === table.id) classes.push('selected');
    if (selectedTables.some(t => t.id === table.id)) classes.push('merge-selected');

    if (table.is_merged && table.parent_table_id) {
      classes.push('merged-child', 'hidden-table');
    } else if (table.merged_tables_ids && table.merged_tables_ids.length > 0) {
      classes.push('merged-parent');
    }

    if (!table.is_online_bookable) classes.push('not-online-bookable');

    return classes.join(' ');
  }

  generateNextTableNumber(tables: Table[]): number {
    const existingNumbers = tables
      .map(t => parseInt(t.table_number))
      .filter(n => !isNaN(n));

    return existingNumbers.length > 0 ? Math.max(...existingNumbers) + 1 : 1;
  }

  async rotateTable(id: string, rotation: number): Promise<boolean> {
    try {
      const normalizedRotation = ((rotation % 360) + 360) % 360;

      // 1. Aggiornamento ottimistico locale
      const currentTables = this.dataSubject.value;
      const updatedTables = currentTables.map(table =>
        table.id === id ? { ...table, rotation: normalizedRotation } : table
      );
      this.dataSubject.next(updatedTables);

      // 2. Aggiornamento database
      const { error } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .update({ rotation: normalizedRotation, updated_at: new Date().toISOString() })
        .eq('id', id);

      if (error) {
        console.error('❌ Database error rotating table:', error);
        // Rollback in caso di errore
        this.dataSubject.next(currentTables);
        return false;
      }

      return true;
    } catch (error) {
      console.error('❌ Error rotating table:', error);
      return false;
    }
  }

  getAllTablesByFloorPlan(floorPlanId: string): Table[] {
    return this.dataSubject.value.filter(table => table.floor_plan_id === floorPlanId);
  }


  calculateMaxCapacity(tables: Table[]): number {
    if (!tables || tables.length === 0) return 0;

    // Somma la capacità di tutti i tavoli attivi
    return tables.reduce((total, table) => {
      return total + (table.capacity || 0);
    }, 0);
  }

  // Calcola la capacità per tipo di tavolo
  getCapacityByTableType(tables: Table[]): { [capacity: number]: number } {
    const capacityMap: { [capacity: number]: number } = {};

    tables.forEach(table => {
      const capacity = table.capacity || 0;
      capacityMap[capacity] = (capacityMap[capacity] || 0) + 1;
    });

    return capacityMap;
  }

  // Ottieni la statistica dei tavoli
  getTableStats(tables: Table[]): {
    totalTables: number;
    maxCapacity: number;
    availableForOnline: number;
    averageCapacity: number;
  } {
    const totalTables = tables.length;
    const maxCapacity = this.calculateMaxCapacity(tables);
    const availableForOnline = tables.filter(t => t.is_online_bookable).length;
    const averageCapacity = totalTables > 0 ? Math.round(maxCapacity / totalTables) : 0;

    return {
      totalTables,
      maxCapacity,
      availableForOnline,
      averageCapacity
    };
  }


  validateTableDimensions(table: Table): { width: number; height: number } {
    let { width, height } = table;

    // Per i cerchi, mantieni altezza uguale alla larghezza
    if (table.shape === 'circle') {
      height = width;
    }
    // Per i quadrati, mantieni altezza uguale alla larghezza
    else if (table.shape === 'square') {
      height = width;
    }

    // Controlla che le dimensioni siano valide
    if (width < 20) width = 20;
    if (width > 1000) width = 1000;
    if (height < 20) height = 20;
    if (height > 1000) height = 1000;

    return { width, height };
  }

  
}